mapper.select:
SELECT TIME as time, RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_PACKETS as txPackets, TX_FLOW as txFlow, NAME as name,
RX_DROP as rxDropCount, TX_DROP as txDropCount, HOST_ID as hostId, CLUSTER_ID as clusterId,
OP_GROUP_ID as operatorGroupId, OP_GROUP_CODE as operatorGroupCode, RX_ERR as rxErrCount, TX_ERR as txErrCount, BANDWIDTH as bandwidth
FROM TBL_VSWITCH_FLOW


        AND NAME =#{name}


        AND HOST_ID =${hostId}


        AND TIME BETWEEN ${startTime} AND ${endTime}



    ORDER BY ${sortField} ASC


    ORDER BY ${sortField} DESC

SELECT TIME as time, RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_PACKETS as txPackets, TX_FLOW as txFlow, NAME as name,
RX_DROP as rxDropCount, TX_DROP as txDropCount, HOST_ID as hostId, CLUSTER_ID as clusterId,
OP_GROUP_ID as operatorGroupId, OP_GROUP_CODE as operatorGroupCode, RX_ERR as rxErrCount, TX_ERR as txErrCount, BANDWIDTH as bandwidth
FROM TBL_VSWITCH_FLOW WHERE TIME=(SELECT MAX(TIME) FROM TBL_VSWITCH_FLOW)-${duration}

    AND NAME =#{name}


    AND HOST_ID =${hostId}


    AND TIME BETWEEN ${startTime} AND ${endTime}


    AND C.OP_GROUP_CODE LIKE #{operatorGroupCode}


    ORDER BY ${sortField} ASC


    ORDER BY ${sortField} DESC
